"5035":{"sizes":"[{\"color\":\"اسود\",\"stock\":\"70\",\"size\":\"M\"},{\"color\":\"اسود\",\"stock\":\"69\",\"size\":\"L\"},{\"color\":\"اسود\",\"stock\":\"68\",\"size\":\"XL\"},{\"color\":\"اسود\",\"stock\":\"62\",\"size\":\"2XL\"},{\"color\":\"ابيض\",\"stock\":\"77\",\"size\":\"M\"},{\"color\":\"ابيض\",\"stock\":\"83\",\"size\":\"L\"},{\"color\":\"ابيض\",\"stock\":\"78\",\"size\":\"XL\"},{\"color\":\"ابيض\",\"stock\":\"77\",\"size\":\"2XL\"}]","desc":"\u003ch1 style=\"color: rgb(52, 73, 94);\"\u003e\u003ca href=\"https://drive.google.com/drive/folders/1y1SV3LITTsaqmFJqPDwas4NUICZ4hOCu\" target=\"_blank\"\u003e\u003cfont color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\"\u003eلينك الميديا\u003c/font\u003e\u003c/a\u003e\u003c/h1\u003e\u003cp\u003e\u003cfont color=\"#000000\" style=\"background-color: rgb(255, 255, 0);\"\u003eUnisex مناسب للجنسين\u0026nbsp;\u003c/font\u003e\u003c/p\u003e\u003cp\u003eخامة أنترلوك (قطن 100%):\u0026nbsp; خامه قطن عالي الجودة، معالج ضد الوبر والانكماش\u0026nbsp; ، نعومة فائقة على الجلد مع قدرة ممتازة على التنفس وامتصاص الرطوبة.\u003c/p\u003e\u003cp\u003eالقوام المثالي: الخامة \"طرية\" جداً في ملمسها، لكنها \"واقفة\" وتحافظ على شكلها لتعطيك المظهر الفخم الذي تبحث عنه.\u003c/p\u003e\u003cp\u003eأفضل تقفيل: اهتمام دقيق بكل التفاصيل، من خياطة الرقبة حتى الأكمام، لضمان متانة القطعة حتى مع الغسيل المتكرر.\u003c/p\u003e\u003cp\u003eقصة أوفر سايز (Oversized Fit): تلبيس مريح وعصري يناسب جميع الأجسام، ويعطيك حرية حركة كاملة مع ستايل \"كاجوال\" شيك جداً.\u003c/p\u003e\u003cp\u003eتصميم \"HERMES\": طباعة احترافية بلمسة عصرية، متوفر باللونين الأبيض والأسود لتناسب كل أطقمك.\u003c/p\u003e\u003cp\u003eتيشرت يجمع بين الشياكة والراحة،خامة ثقيلة ومحترمة، وتصميم بيفضل محافظ على رونقه وشكله \"الواقف\" طول اليوم.\u003c/p\u003e\u003cp\u003eتلبيس محترم\u0026nbsp;\u003c/p\u003e\u003cp\u003eM 50:60\u003c/p\u003e\u003cp\u003eL 60:70\u003c/p\u003e\u003cp\u003eXL 70:80\u003c/p\u003e\u003cp\u003e2XL 80:90\u003c/p\u003e"},
